module frequency_divider (
    input wire clk,
    input wire rst,
    output reg out
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            out <= 0;
        end else begin
            out <= ~out;
        end
    end
endmodule
